1	// game-of-life.ts
2	export type Cell = [number, number];
3	
4	const isNeighbor = ([x, y]: Cell, [nx, ny]: Cell): boolean =>
5	  Math.abs(nx - x) <= 1 && Math.abs(ny - y) <= 1 && !(nx === x && ny === y);
6	
7	const NEIGHBORHOOD_OFFSETS = [-1, 0, 1];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborhoodOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBORHOOD_OFFSETS.flatMap((dx) =>
13	    NEIGHBORHOOD_OFFSETS.map((dy): Cell => [x + dx, y + dy])
14	  );
15	
16	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
17	  const countLiveNeighbors = (cell: Cell): number =>
18	    liveCells.filter((other) => isNeighbor(cell, other)).length;
19	
20	  const livesInNextGeneration = (cell: Cell): boolean =>
21	    countLiveNeighbors(cell) === 3;
22	
23	  const candidates = new Map(
24	    liveCells
25	      .flatMap(neighborhoodOf)
26	      .map((cell): [string, Cell] => [cellKey(cell), cell])
27	  );
28	
29	  return [...candidates.values()].filter(livesInNextGeneration);
30	};
