2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Game of Life - Next Generation", () => {
6	  it("should return an empty array for an empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should let a single live cell die (underpopulation)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should let two neighboring cells die, each having only one live neighbor (underpopulation)", () => {
13	    expect(
14	      nextGeneration([
15	        [0, 1],
16	        [1, 1],
17	      ])
18	    ).toEqual([]);
19	  });
20	  it("should keep a live cell with three live neighbors alive (survival)", () => {
21	    expect(
22	      nextGeneration([
23	        [0, 0],
24	        [1, 0],
25	        [2, 0],
26	        [1, 1],
27	      ])
28	    ).toContainEqual([1, 1]);
29	  });
30	  it("should let a live cell with four live neighbors die (overpopulation)", () => {
31	    expect(
32	      nextGeneration([
33	        [0, 0],
34	        [0, 1],
35	        [0, 2],
36	        [1, 0],
37	        [1, 1],
38	      ])
39	    ).not.toContainEqual([1, 1]);
40	  });
41	  it("should bring a dead cell with exactly three live neighbors to life (reproduction)", () => {
42	    expect(
43	      nextGeneration([
44	        [0, 0],
45	        [1, 0],
46	        [0, 1],
47	      ])
48	    ).toContainEqual([1, 1]);
49	  });
50	  it("should keep a block still life unchanged", () => {
51	    const result = nextGeneration([
52	      [0, 0],
53	      [1, 0],
54	      [0, 1],
55	      [1, 1],
56	    ]);
57	    expect(result).toHaveLength(4);
58	    expect(result).toContainEqual([0, 0]);
59	    expect(result).toContainEqual([1, 0]);
60	    expect(result).toContainEqual([0, 1]);
61	    expect(result).toContainEqual([1, 1]);
62	  });
63	  it("should oscillate a vertical blinker into a horizontal blinker with negative coordinates", () => {
64	    const result = nextGeneration([
65	      [0, 0],
66	      [0, 1],
67	      [0, 2],
68	    ]);
69	    expect(result).toHaveLength(3);
70	    expect(result).toContainEqual([-1, 1]);
71	    expect(result).toContainEqual([0, 1]);
72	    expect(result).toContainEqual([1, 1]);
73	  });
74	});
