const liveKeys = new Set(liveCells.map(cellKey));

const livesInNextGeneration = (cell: Cell): boolean => {
  const liveNeighbors = countLiveNeighbors(cell);
  return (
    liveNeighbors === 3 || (liveNeighbors === 2 && liveKeys.has(cellKey(cell)))
  );
};
